// ── Helpers ──────────────────────────────────────────────────

/** Get SVG string by icon ID — searches both ICON_BANK and SKILL_ICONS */
export function getIcon(id: string): string {
  return ICON_BANK[id] ?? SKILL_ICONS[id] ?? ICON_BANK[id?.toLowerCase()] ?? SKILL_ICONS[id?.toLowerCase()] ?? ICON_BANK.mystery
}

/** Total icons in bank */
export const ICON_COUNT = Object.keys(ICON_BANK).length

/** React component for rendering an icon from the bank */
let _iconUid = 0
export function IconSVG({ id, size = 38, className }: { id: string; size?: number; className?: string }) {
  const uid = ++_iconUid
  let svg = getIcon(id)
  // Make all internal IDs unique to prevent gradient conflicts across instances
  svg = svg.replace(/id="([^"]+)"/g, (_, gid) => `id="${gid}_${uid}"`)
  svg = svg.replace(/url\(#([^)]+)\)/g, (_, gid) => `url(#${gid}_${uid})`)
  svg = svg.replace(/href="#([^"]+)"/g, (_, gid) => `href="#${gid}_${uid}"`)
  return (
    <div
      className={className}
      style={{ width: size, height: size, flexShrink: 0 }}
      dangerouslySetInnerHTML={{ __html: svg }}
    />
  )
}

// ── Resource icon helper ──
/** Get resource SVG icon by resource ID (maps res_xxx from iconBank) */
export function getResourceIcon(resourceId: string): string {
  return ICON_BANK[`res_${resourceId}`] ?? ICON_BANK.mystery
}

/** React component for rendering a resource icon */
export function ResourceIconSVG({ resourceId, size = 24 }: { resourceId: string; size?: number }) {
  const svg = getResourceIcon(resourceId)
  return (
    <div
      style={{ width: size, height: size, flexShrink: 0 }}
      dangerouslySetInnerHTML={{ __html: svg }}
    />
  )
}

// ── Skill icon helper ──
/** Get skill SVG icon by skill ID. Falls back to a default icon. */
export function getSkillIcon(skillId: string): string {
  return SKILL_ICONS[skillId] ?? `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="8"/><circle cx="12" cy="12" r="3"/></svg>`
}

/** React component for rendering a skill tree icon (monochrome, inherits color) */
export function SkillIconSVG({ skillId, size = 20, color }: { skillId: string; size?: number; color?: string }) {
  const svg = getSkillIcon(skillId)
  return (
    <div
      style={{ width: size, height: size, flexShrink: 0, color: color ?? 'currentColor' }}
      dangerouslySetInnerHTML={{ __html: svg }}
    />
  )
}
